package core

// Warning represents a non-fatal warning generated by the core service.
type Warning string

// NextAction represents a suggested subsequent step for the user or agent.
type NextAction string

// Result is the unified, surface-agnostic envelope returned by all Service methods.
// It directly maps to the response envelope specified in SPEC §8.2.
type Result struct {
	OK          bool         `json:"ok"`
	Data        any          `json:"data,omitempty"`
	Warnings    []Warning    `json:"warnings,omitempty"`
	NextActions []NextAction `json:"next_actions,omitempty"`
}
